// src/services/api.js
import axios from "axios";

const API_URL = process.env.REACT_APP_API_URL || "http://localhost:8080/api";

// ✅ Get token from storage (supports both localStorage and sessionStorage)
const getToken = () => {
  return localStorage.getItem("token") || sessionStorage.getItem("token");
};

const api = axios.create({
  baseURL: API_URL,
  headers: {
    "Content-Type": "application/json",
  },
});

// ✅ Add request interceptor to attach token automatically
api.interceptors.request.use(
  (config) => {
    const token = getToken();
    if (token && token !== "null" && token !== "undefined") {
      config.headers.Authorization = `Bearer ${token}`;
    }
    return config;
  },
  (error) => {
    return Promise.reject(error);
  }
);

// ✅ Add response interceptor to handle 401/403 errors
api.interceptors.response.use(
  (response) => response,
  (error) => {
    if (error.response?.status === 401 || error.response?.status === 403) {
      // Clear invalid token and redirect to login
      localStorage.removeItem("token");
      sessionStorage.removeItem("token");
      window.location.href = "/login";
    }
    return Promise.reject(error);
  }
);

// Remove manual token headers from individual methods
api.getVehicles = async () => {
  const response = await api.get("/vehicles");
  return response.data;
};

api.getAlerts = async () => {
  const response = await api.get("/alerts");
  return response.data;
};

api.optimizeRoute = async (routeRequest) => {
  const response = await api.post("/routes/optimize", routeRequest);
  return response.data;
};

api.geocode = async (address) => {
  const response = await api.get(`/geocode?address=${encodeURIComponent(address)}`);
  return response.data;
};

export default api;
